"""
Parameterized generator for GH892_dask_9871.

Source PR:    https://github.com/dask/dask/pull/9871
Source Issue: https://github.com/dask/dask/issues/9870

Seed varies: renames 'annotations' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH892_dask_9871'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH892_dask_9871'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('annotations', 'annotations' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH892_dask_9871',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'dask/dask',
                "pr_number": 9871,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/dask/dask/pull/9871",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'dask/layers.py': 'from __future__ import annotations\n\nimport functools\nimport math\nimport operator\nfrom collections import defaultdict\nfrom collections.abc import Callable\nfrom itertools import product\nfrom typing import Any\n\nimport tlz as toolz\nfrom tlz.curried import map\n\nfrom dask.base import tokenize\nfrom dask.blockwise import Blockwise, BlockwiseDep, BlockwiseDepDict, blockwise_token\nfrom dask.core import flatten, keys_in_tasks\nfrom dask.highlevelgraph import Layer\nfrom dask.utils import (\n    apply,\n    cached_cumsum,\n    concrete,\n    insert,\n    stringify,\n    stringify_collection_keys,\n)\n\n#\n##\n###  General Utilities\n##\n#\n\n\nclass CallableLazyImport:\n    """Function Wrapper for Lazy Importing.\n\n    This Class should only be used when materializing a graph\n    on a distributed scheduler.\n    """\n\n    def __init__(self, function_path):\n        self.function_path = function_path\n\n    def __call__(self, *args, **kwargs):\n        from distributed.utils import import_term\n\n        return import_term(self.function_path)(*args, **kwargs)\n\n\n#\n##\n###  Array Layers & Utilities\n##\n#\n\n\nclass ArrayBlockwiseDep(BlockwiseDep):\n    """\n    Blockwise dep for array-likes, which only needs chunking\n    information to compute its data.\n    """\n\n    chunks: tuple[tuple[int, ...], ...]\n    numblocks: tuple[int, ...]\n    produces_tasks: bool = False\n\n    def __init__(self, chunks: tuple[tuple[int, ...], ...]):\n        self.chunks = chunks\n        self.numblocks = tuple(len(chunk) for chunk in chunks)\n        self.produces_tasks = False\n\n    def __getitem__(self, idx: tuple[int, ...]):\n        raise NotImplementedError("Subclasses must implement __getitem__")\n\n    def __dask_distributed_pack__(\n        self, required_indices: list[tuple[int, ...]] | None = None\n    ):\n        return {"chunks": self.chunks}\n\n    @classmethod\n    def __dask_distributed_unpack__(cls, state):\n        return cls(**state)\n\n\nclass ArrayChunkShapeDep(ArrayBlockwiseDep):\n    """Produce chunk shapes given a chunk index"""\n\n    def __getitem__(self, idx: tuple[int, ...]):\n        return tuple(chunk[i] for i, chunk in zip(idx, self.chunks))\n\n\nclass ArraySliceDep(ArrayBlockwiseDep):\n    """Produce slice(s) into the full-sized array given a chunk index"""\n\n    starts: tuple[tuple[int, ...], ...]\n\n    def __init__(self, chunks: tuple[tuple[int, ...], ...]):\n        super().__init__(chunks)\n        self.starts = tuple(cached_cumsum(c, initial_zero=True) for c in chunks)\n\n    def __getitem__(self, idx: tuple):\n        loc = tuple((start[i], start[i + 1]) for i, start in zip(idx, self.starts))\n        return tuple(slice(*s, None) for s in loc)\n\n\nclass ArrayOverlapLayer(Layer):\n    """Simple HighLevelGraph array overlap layer.\n\n    Lazily computed High-level graph layer for a array overlap operations.\n\n    Parameters\n    ----------\n    name : str\n        Name of new output overlap array.\n    array : Dask array\n    axes: Mapping\n        Axes dictionary indicating overlap in each dimension,\n        e.g. ``{\'0\': 1, \'1\': 1}``\n    """\n\n    def __init__(\n        self,\n        name,\n        axes,\n        chunks,\n        numblocks,\n        token,\n    ):\n        super().__init__()\n        self.name = name\n        self.axes = axes\n        self.chunks = chunks\n        self.numblocks = numblocks\n        self.token = token\n        self._cached_keys = None\n\n    def __repr__(self):\n        return f"ArrayOverlapLayer<name=\'{self.name}\'"\n\n    @property\n    def _dict(self):\n        """Materialize full dict representation"""\n        if hasattr(self, "_cached_dict"):\n            return self._cached_dict\n        else:\n            dsk = self._construct_graph()\n            self._cached_dict = dsk\n        return self._cached_dict\n\n    def __getitem__(self, key):\n        return self._dict[key]\n\n    def __iter__(self):\n        return iter(self._dict)\n\n    def __len__(self):\n        return len(self._dict)\n\n    def is_materialized(self):\n        return hasattr(self, "_cached_dict")\n\n    def get_output_keys(self):\n        return self.keys()  # FIXME! this implementation materializes the graph\n\n    def _dask_keys(self):\n        if self._cached_keys is not None:\n            return self._cached_keys\n\n        name, chunks, numblocks = self.name, self.chunks, self.numblocks\n\n        def keys(*args):\n            if not chunks:\n                return [(name,)]\n            ind = len(args)\n            if ind + 1 == len(numblocks):\n                result = [(name,) + args + (i,) for i in range(numblocks[ind])]\n            else:\n                result = [keys(*(args + (i,))) for i in range(numblocks[ind])]\n            return result\n\n        self._cached_keys = result = keys()\n        return result\n\n    def _construct_graph(self, deserializing=False):\n        """Construct graph for a simple overlap operation."""\n        axes = self.axes\n        chunks = self.chunks\n        name = self.name\n        dask_keys = self._dask_keys()\n\n        getitem_name = "getitem-" + self.token\n        overlap_name = "overlap-" + self.token\n\n        if deserializing:\n            # Use CallableLazyImport objects to avoid importing dataframe\n            # module on the scheduler\n            concatenate3 = CallableLazyImport("dask.array.core.concatenate3")\n        else:\n            # Not running on distributed scheduler - Use explicit functions\n            from dask.array.core import concatenate3\n\n        dims = list(map(len, chunks))\n        expand_key2 = functools.partial(\n            _expand_keys_around_center, dims=dims, axes=axes\n        )\n\n        # Make keys for each of the surrounding sub-arrays\n        interior_keys = toolz.pipe(\n            dask_keys, flatten, map(expand_key2), map(flatten), toolz.concat, list\n        )\n        interior_slices = {}\n        overlap_blocks = {}\n        for k in interior_keys:\n            frac_slice = fractional_slice((name,) + k, axes)\n            if (name,) + k != frac_slice:\n                interior_slices[(getitem_name,) + k] = frac_slice\n            else:\n                interior_slices[(getitem_name,) + k] = (name,) + k\n                overlap_blocks[(overlap_name,) + k] = (\n                    concatenate3,\n                    (concrete, expand_key2((None,) + k, name=getitem_name)),\n                )\n\n        dsk = toolz.merge(interior_slices, overlap_blocks)\n        return dsk\n\n    @classmethod\n    def __dask_distributed_unpack__(cls, state):\n        return cls(**state)._construct_graph(deserializing=True)\n\n\ndef _expand_keys_around_center(k, dims, name=None, axes=None):\n    """Get all neighboring keys around center\n\n    Parameters\n    ----------\n    k: tuple\n        They key around which to generate new keys\n    dims: Sequence[int]\n        The number of chunks in each dimension\n    name: Option[str]\n        The name to include in the output keys, or none to include no name\n    axes: Dict[int, int]\n        The axes active in the expansion.  We don\'t expand on non-active axes\n\n    Examples\n    --------\n    >>> _expand_keys_around_center((\'x\', 2, 3), dims=[5, 5], name=\'y\', axes={0: 1, 1: 1})  # noqa: E501 # doctest: +NORMALIZE_WHITESPACE\n    [[(\'y\', 1.1, 2.1), (\'y\', 1.1, 3), (\'y\', 1.1, 3.9)],\n     [(\'y\',   2, 2.1), (\'y\',   2, 3), (\'y\',   2, 3.9)],\n     [(\'y\', 2.9, 2.1), (\'y\', 2.9, 3), (\'y\', 2.9, 3.9)]]\n\n    >>> _expand_keys_around_center((\'x\', 0, 4), dims=[5, 5], name=\'y\', axes={0: 1, 1: 1})  # noqa: E501 # doctest: +NORMALIZE_WHITESPACE\n    [[(\'y\',   0, 3.1), (\'y\',   0,   4)],\n     [(\'y\', 0.9, 3.1), (\'y\', 0.9,   4)]]\n    """\n\n    def inds(i, ind):\n        rv = []\n        if ind - 0.9 > 0:\n            rv.append(ind - 0.9)\n        rv.append(ind)\n        if ind + 0.9 < dims[i] - 1:\n            rv.append(ind + 0.9)\n        return rv\n\n    shape = []\n    for i, ind in enumerate(k[1:]):\n        num = 1\n        if ind > 0:\n            num += 1\n        if ind < dims[i] - 1:\n            num += 1\n        shape.append(num)\n\n    args = [\n        inds(i, ind) if any((axes.get(i, 0),)) else [ind] for i, ind in enumerate(k[1:])\n    ]\n    if name is not None:\n        args = [[name]] + args\n    seq = list(product(*args))\n    shape2 = [d if any((axes.get(i, 0),)) else 1 for i, d in enumerate(shape)]\n    result = reshapelist(shape2, seq)\n    return result\n\n\ndef reshapelist(shape, seq):\n    """Reshape iterator to nested shape\n\n    >>> reshapelist((2, 3), range(6))\n    [[0, 1, 2], [3, 4, 5]]\n    """\n    if len(shape) == 1:\n        return list(seq)\n    else:\n        n = int(len(seq) / shape[0])\n        return [reshapelist(shape[1:], part) for part in toolz.partition(n, seq)]\n\n\ndef fractional_slice(task, axes):\n    """\n\n    >>> fractional_slice((\'x\', 5.1), {0: 2})\n    (<built-in function getitem>, (\'x\', 5), (slice(-2, None, None),))\n\n    >>> fractional_slice((\'x\', 3, 5.1), {0: 2, 1: 3})\n    (<built-in function getitem>, (\'x\', 3, 5), (slice(None, None, None), slice(-3, None, None)))\n\n    >>> fractional_slice((\'x\', 2.9, 5.1), {0: 2, 1: 3})\n    (<built-in function getitem>, (\'x\', 3, 5), (slice(0, 2, None), slice(-3, None, None)))\n    """\n    rounded = (task[0],) + tuple(int(round(i)) for i in task[1:])\n\n    index = []\n    for i, (t, r) in enumerate(zip(task[1:], rounded[1:])):\n        depth = axes.get(i, 0)\n        if isinstance(depth, tuple):\n            left_depth = depth[0]\n            right_depth = depth[1]\n        else:\n            left_depth = depth\n            right_depth = depth\n\n        if t == r:\n            index.append(slice(None, None, None))\n        elif t < r and right_depth:\n            index.append(slice(0, right_depth))\n        elif t > r and left_depth:\n            index.append(slice(-left_depth, None))\n        else:\n            index.append(slice(0, 0))\n    index = tuple(index)\n\n    if all(ind == slice(None, None, None) for ind in index):\n        return task\n    else:\n        return (operator.getitem, rounded, index)\n\n\n#\n##\n###  DataFrame Layers & Utilities\n##\n#\n\n\nclass SimpleShuffleLayer(Layer):\n    """Simple HighLevelGraph Shuffle layer\n\n    High-level graph layer for a simple shuffle operation in which\n    each output partition depends on all input partitions.\n\n    Parameters\n    ----------\n    name : str\n        Name of new shuffled output collection.\n    column : str or list of str\n        Column(s) to be used to map rows to output partitions (by hashing).\n    npartitions : int\n        Number of output partitions.\n    npartitions_input : int\n        Number of partitions in the original (un-shuffled) DataFrame.\n    ignore_index: bool, default False\n        Ignore index during shuffle.  If ``True``, performance may improve,\n        but index values will not be preserved.\n    name_input : str\n        Name of input collection.\n    meta_input : pd.DataFrame-like object\n        Empty metadata of input collection.\n    parts_out : list of int (optional)\n        List of required output-partition indices.\n    annotations : dict (optional)\n        Layer annotations\n    """\n\n    def __init__(\n        self,\n        name,\n        column,\n        npartitions,\n        npartitions_input,\n        ignore_index,\n        name_input,\n        meta_input,\n        parts_out=None,\n        annotations=None,\n    ):\n        super().__init__(annotations=annotations)\n        self.name = name\n        self.column = column\n        self.npartitions = npartitions\n        self.npartitions_input = npartitions_input\n        self.ignore_index = ignore_index\n        self.name_input = name_input\n        self.meta_input = meta_input\n        self.parts_out = parts_out or range(npartitions)\n        self.split_name = "split-" + self.name\n\n        # The scheduling policy of Dask is generally depth-first,\n        # which works great in most cases. However, in case of shuffle,\n        # it increases the memory usage significantly. This is because\n        # depth-first delays the freeing of the result of `shuffle_group()`\n        # until the end of the shuffling.\n        #\n        # We address this by manually setting a high "priority" to the\n        # `getitem()` ("split") tasks, using annotations. This forces a\n        # breadth-first scheduling of the tasks that directly depend on\n        # the `shuffle_group()` output, allowing that data to be freed\n        # much earlier.\n        #\n        # See https://github.com/dask/dask/pull/6051 for a detailed discussion.\n        self.annotations = self.annotations or {}\n        if "priority" not in self.annotations:\n            self.annotations["priority"] = {}\n        self.annotations["priority"]["__expanded_annotations__"] = None\n        self.annotations["priority"].update({_key: 1 for _key in self.get_split_keys()})\n\n    def get_split_keys(self):\n        # Return SimpleShuffleLayer "split" keys\n        return [\n            stringify((self.split_name, part_out, part_in))\n            for part_in in range(self.npartitions_input)\n            for part_out in self.parts_out\n        ]\n\n    def get_output_keys(self):\n        return {(self.name, part) for part in self.parts_out}\n\n    def __repr__(self):\n        return "SimpleShuffleLayer<name=\'{}\', npartitions={}>".format(\n            self.name, self.npartitions\n        )\n\n    def is_materialized(self):\n        return hasattr(self, "_cached_dict")\n\n    @property\n    def _dict(self):\n        """Materialize full dict representation"""\n        if hasattr(self, "_cached_dict"):\n            return self._cached_dict\n        else:\n            dsk = self._construct_graph()\n            self._cached_dict = dsk\n        return self._cached_dict\n\n    def __getitem__(self, key):\n        return self._dict[key]\n\n    def __iter__(self):\n        return iter(self._dict)\n\n    def __len__(self):\n        return len(self._dict)\n\n    def _keys_to_parts(self, keys):\n        """Simple utility to convert keys to partition indices."""\n        parts = set()\n        for key in keys:\n            try:\n                _name, _part = key\n            except ValueError:\n                continue\n            if _name != self.name:\n                continue\n            parts.add(_part)\n        return parts\n\n    def _cull_dependencies(self, keys, parts_out=None):\n        """Determine the necessary dependencies to produce `keys`.\n\n        For a simple shuffle, output partitions always depend on\n        all input partitions. This method does not require graph\n        materialization.\n        """\n        deps = defaultdict(set)\n        parts_out = parts_out or self._keys_to_parts(keys)\n        for part in parts_out:\n            deps[(self.name, part)] |= {\n                (self.name_input, i) for i in range(self.npartitions_input)\n            }\n        return deps\n\n    def _cull(self, parts_out):\n        return SimpleShuffleLayer(\n            self.name,\n            self.column,\n            self.npartitions,\n            self.npartitions_input,\n            self.ignore_index,\n            self.name_input,\n            self.meta_input,\n            parts_out=parts_out,\n        )\n\n    def cull(self, keys, all_keys):\n        """Cull a SimpleShuffleLayer HighLevelGraph layer.\n\n        The underlying graph will only include the necessary\n        tasks to produce the keys (indices) included in `parts_out`.\n        Therefore, "culling" the layer only requires us to reset this\n        parameter.\n        """\n        parts_out = self._keys_to_parts(keys)\n        culled_deps = self._cull_dependencies(keys, parts_out=parts_out)\n        if parts_out != set(self.parts_out):\n            culled_layer = self._cull(parts_out)\n            return culled_layer, culled_deps\n        else:\n            return self, culled_deps\n\n    def __reduce__(self):\n        attrs = [\n            "name",\n            "column",\n            "npartitions",\n            "npartitions_input",\n            "ignore_index",\n            "name_input",\n            "meta_input",\n            "parts_out",\n            "annotations",\n        ]\n        return (SimpleShuffleLayer, tuple(getattr(self, attr) for attr in attrs))\n\n    def __dask_distributed_pack__(\n        self, all_hlg_keys, known_key_dependencies, client, client_keys\n    ):\n        from distributed.protocol.serialize import to_serialize\n\n        return {\n            "name": self.name,\n            "column": self.column,\n            "npartitions": self.npartitions,\n            "npartitions_input": self.npartitions_input,\n            "ignore_index": self.ignore_index,\n            "name_input": self.name_input,\n            "meta_input": to_serialize(self.meta_input),\n            "parts_out": list(self.parts_out),\n        }\n\n    @classmethod\n    def __dask_distributed_unpack__(cls, state, dsk, dependencies):\n        from distributed.worker import dumps_task\n\n        # msgpack will convert lists into tuples, here\n        # we convert them back to lists\n        if isinstance(state["column"], tuple):\n            state["column"] = list(state["column"])\n        if "inputs" in state:\n            state["inputs"] = list(state["inputs"])\n\n        # Materialize the layer\n        layer_dsk = cls(**state)._construct_graph(deserializing=True)\n\n        # Convert all keys to strings and dump tasks\n        layer_dsk = {\n            stringify(k): stringify_collection_keys(v) for k, v in layer_dsk.items()\n        }\n        keys = layer_dsk.keys() | dsk.keys()\n\n        # TODO: use shuffle-knowledge to calculate dependencies more efficiently\n        deps = {k: keys_in_tasks(keys, [v]) for k, v in layer_dsk.items()}\n\n        return {"dsk": toolz.valmap(dumps_task, layer_dsk), "deps": deps}\n\n    def _construct_graph(self, deserializing=False):\n        """Construct graph for a simple shuffle operation."""\n\n        shuffle_group_name = "group-" + self.name\n\n        if deserializing:\n            # Use CallableLazyImport objects to avoid importing dataframe\n            # module on the scheduler\n            concat_func = CallableLazyImport("dask.dataframe.core._concat")\n            shuffle_group_func = CallableLazyImport(\n                "dask.dataframe.shuffle.shuffle_group"\n            )\n        else:\n            # Not running on distributed scheduler - Use explicit functions\n            from dask.dataframe.core import _concat as concat_func\n            from dask.dataframe.shuffle import shuffle_group as shuffle_group_func\n\n        dsk = {}\n        for part_out in self.parts_out:\n            _concat_list = [\n                (self.split_name, part_out, part_in)\n                for part_in in range(self.npartitions_input)\n            ]\n            dsk[(self.name, part_out)] = (\n                concat_func,\n                _concat_list,\n                self.ignore_index,\n            )\n            for _, _part_out, _part_in in _concat_list:\n                dsk[(self.split_name, _part_out, _part_in)] = (\n                    operator.getitem,\n                    (shuffle_group_name, _part_in),\n                    _part_out,\n                )\n                if (shuffle_group_name, _part_in) not in dsk:\n                    dsk[(shuffle_group_name, _part_in)] = (\n                        shuffle_group_func,\n                        (self.name_input, _part_in),\n                        self.column,\n                        0,\n                        self.npartitions,\n                        self.npartitions,\n                        self.ignore_index,\n                        self.npartitions,\n                    )\n\n        return dsk\n\n\nclass ShuffleLayer(SimpleShuffleLayer):\n    """Shuffle-stage HighLevelGraph layer\n\n    High-level graph layer corresponding to a single stage of\n    a multi-stage inter-partition shuffle operation.\n\n    Stage: (shuffle-group) -> (shuffle-split) -> (shuffle-join)\n\n    Parameters\n    ----------\n    name : str\n        Name of new (partially) shuffled collection.\n    column : str or list of str\n        Column(s) to be used to map rows to output partitions (by hashing).\n    inputs : list of tuples\n        Each tuple dictates the data movement for a specific partition.\n    stage : int\n        Index of the current shuffle stage.\n    npartitions : int\n        Number of output partitions for the full (multi-stage) shuffle.\n    npartitions_input : int\n        Number of partitions in the original (un-shuffled) DataFrame.\n    k : int\n        A partition is split into this many groups during each stage.\n    ignore_index: bool, default False\n        Ignore index during shuffle.  If ``True``, performance may improve,\n        but index values will not be preserved.\n    name_input : str\n        Name of input collection.\n    meta_input : pd.DataFrame-like object\n        Empty metadata of input collection.\n    parts_out : list of int (optional)\n        List of required output-partition indices.\n    annotations : dict (optional)\n        Layer annotations\n    """\n\n    def __init__(\n        self,\n        name,\n        column,\n        inputs,\n        stage,\n        npartitions,\n        npartitions_input,\n        nsplits,\n        ignore_index,\n        name_input,\n        meta_input,\n        parts_out=None,\n        annotations=None,\n    ):\n        self.inputs = inputs\n        self.stage = stage\n        self.nsplits = nsplits\n        super().__init__(\n            name,\n            column,\n            npartitions,\n            npartitions_input,\n            ignore_index,\n            name_input,\n            meta_input,\n            parts_out=parts_out or range(len(inputs)),\n            annotations=annotations,\n        )\n\n    def get_split_keys(self):\n        # Return ShuffleLayer "split" keys\n        keys = []\n        for part in self.parts_out:\n            out = self.inputs[part]\n            for i in range(self.nsplits):\n                keys.append(\n                    stringify(\n                        (\n                            self.split_name,\n                            out[self.stage],\n                            insert(out, self.stage, i),\n                        )\n                    )\n                )\n        return keys\n\n    def __repr__(self):\n        return "ShuffleLayer<name=\'{}\', stage={}, nsplits={}, npartitions={}>".format(\n            self.name, self.stage, self.nsplits, self.npartitions\n        )\n\n    def __reduce__(self):\n        attrs = [\n            "name",\n            "column",\n            "inputs",\n            "stage",\n            "npartitions",\n            "npartitions_input",\n            "nsplits",\n            "ignore_index",\n            "name_input",\n            "meta_input",\n            "parts_out",\n            "annotations",\n        ]\n\n        return (ShuffleLayer, tuple(getattr(self, attr) for attr in attrs))\n\n    def __dask_distributed_pack__(self, *args, **kwargs):\n        ret = super().__dask_distributed_pack__(*args, **kwargs)\n        ret["inputs"] = self.inputs\n        ret["stage"] = self.stage\n        ret["nsplits"] = self.nsplits\n        return ret\n\n    def _cull_dependencies(self, keys, parts_out=None):\n        """Determine the necessary dependencies to produce `keys`.\n\n        Does not require graph materialization.\n        """\n        deps = defaultdict(set)\n        parts_out = parts_out or self._keys_to_parts(keys)\n        inp_part_map = {inp: i for i, inp in enumerate(self.inputs)}\n        for part in parts_out:\n            out = self.inputs[part]\n            for k in range(self.nsplits):\n                _inp = insert(out, self.stage, k)\n                _part = inp_part_map[_inp]\n                if self.stage == 0 and _part >= self.npartitions_input:\n                    deps[(self.name, part)].add(("group-" + self.name, _inp, "empty"))\n                else:\n                    deps[(self.name, part)].add((self.name_input, _part))\n        return deps\n\n    def _cull(self, parts_out):\n        return ShuffleLayer(\n            self.name,\n            self.column,\n            self.inputs,\n            self.stage,\n            self.npartitions,\n            self.npartitions_input,\n            self.nsplits,\n            self.ignore_index,\n            self.name_input,\n            self.meta_input,\n            parts_out=parts_out,\n        )\n\n    def _construct_graph(self, deserializing=False):\n        """Construct graph for a "rearrange-by-column" stage."""\n\n        shuffle_group_name = "group-" + self.name\n\n        if deserializing:\n            # Use CallableLazyImport objects to avoid importing dataframe\n            # module on the scheduler\n            concat_func = CallableLazyImport("dask.dataframe.core._concat")\n            shuffle_group_func = CallableLazyImport(\n                "dask.dataframe.shuffle.shuffle_group"\n            )\n        else:\n            # Not running on distributed scheduler - Use explicit functions\n            from dask.dataframe.core import _concat as concat_func\n            from dask.dataframe.shuffle import shuffle_group as shuffle_group_func\n\n        dsk = {}\n        inp_part_map = {inp: i for i, inp in enumerate(self.inputs)}\n        for part in self.parts_out:\n\n            out = self.inputs[part]\n\n            _concat_list = []  # get_item tasks to concat for this output partition\n            for i in range(self.nsplits):\n                # Get out each individual dataframe piece from the dicts\n                _inp = insert(out, self.stage, i)\n                _idx = out[self.stage]\n                _concat_list.append((self.split_name, _idx, _inp))\n\n            # concatenate those pieces together, with their friends\n            dsk[(self.name, part)] = (\n                concat_func,\n                _concat_list,\n                self.ignore_index,\n            )\n\n            for _, _idx, _inp in _concat_list:\n                dsk[(self.split_name, _idx, _inp)] = (\n                    operator.getitem,\n                    (shuffle_group_name, _inp),\n                    _idx,\n                )\n\n                if (shuffle_group_name, _inp) not in dsk:\n\n                    # Initial partitions (output of previous stage)\n                    _part = inp_part_map[_inp]\n                    if self.stage == 0:\n                        if _part < self.npartitions_input:\n                            input_key = (self.name_input, _part)\n                        else:\n                            # In order to make sure that to_serialize() serialize the\n                            # empty dataframe input, we add it as a key.\n                            input_key = (shuffle_group_name, _inp, "empty")\n                            dsk[input_key] = self.meta_input\n                    else:\n                        input_key = (self.name_input, _part)\n\n                    # Convert partition into dict of dataframe pieces\n                    dsk[(shuffle_group_name, _inp)] = (\n                        shuffle_group_func,\n                        input_key,\n                        self.column,\n                        self.stage,\n                        self.nsplits,\n                        self.npartitions_input,\n                        self.ignore_index,\n                        self.npartitions,\n                    )\n\n        return dsk\n\n\nclass BroadcastJoinLayer(Layer):\n    """Broadcast-based Join Layer\n\n    High-level graph layer for a join operation requiring the\n    smaller collection to be broadcasted to every partition of\n    the larger collection.\n\n    Parameters\n    ----------\n    name : str\n        Name of new (joined) output collection.\n    lhs_name: string\n        "Left" DataFrame collection to join.\n    lhs_npartitions: int\n        Number of partitions in "left" DataFrame collection.\n    rhs_name: string\n        "Right" DataFrame collection to join.\n    rhs_npartitions: int\n        Number of partitions in "right" DataFrame collection.\n    parts_out : list of int (optional)\n        List of required output-partition indices.\n    annotations : dict (optional)\n        Layer annotations.\n    **merge_kwargs : **dict\n        Keyword arguments to be passed to chunkwise merge func.\n    """\n\n    def __init__(\n        self,\n        name,\n        npartitions,\n        lhs_name,\n        lhs_npartitions,\n        rhs_name,\n        rhs_npartitions,\n        parts_out=None,\n        annotations=None,\n        **merge_kwargs,\n    ):\n        super().__init__(annotations=annotations)\n        self.name = name\n        self.npartitions = npartitions\n        self.lhs_name = lhs_name\n        self.lhs_npartitions = lhs_npartitions\n        self.rhs_name = rhs_name\n        self.rhs_npartitions = rhs_npartitions\n        self.parts_out = parts_out or set(range(self.npartitions))\n        self.merge_kwargs = merge_kwargs\n        self.how = self.merge_kwargs.get("how")\n        self.left_on = self.merge_kwargs.get("left_on")\n        self.right_on = self.merge_kwargs.get("right_on")\n        if isinstance(self.left_on, list):\n            self.left_on = (list, tuple(self.left_on))\n        if isinstance(self.right_on, list):\n            self.right_on = (list, tuple(self.right_on))\n\n    def get_output_keys(self):\n        return {(self.name, part) for part in self.parts_out}\n\n    def __repr__(self):\n        return "BroadcastJoinLayer<name=\'{}\', how={}, lhs={}, rhs={}>".format(\n            self.name, self.how, self.lhs_name, self.rhs_name\n        )\n\n    def is_materialized(self):\n        return hasattr(self, "_cached_dict")\n\n    @property\n    def _dict(self):\n        """Materialize full dict representation"""\n        if hasattr(self, "_cached_dict"):\n            return self._cached_dict\n        else:\n            dsk = self._construct_graph()\n            self._cached_dict = dsk\n        return self._cached_dict\n\n    def __getitem__(self, key):\n        return self._dict[key]\n\n    def __iter__(self):\n        return iter(self._dict)\n\n    def __len__(self):\n        return len(self._dict)\n\n    def __dask_distributed_pack__(self, *args, **kwargs):\n        import pickle\n\n        # Pickle complex merge_kwargs elements. Also\n        # tuples, which may be confused with keys.\n        _merge_kwargs = {}\n        for k, v in self.merge_kwargs.items():\n            if not isinstance(v, (str, list, bool)):\n                _merge_kwargs[k] = pickle.dumps(v)\n            else:\n                _merge_kwargs[k] = v\n\n        return {\n            "name": self.name,\n            "npartitions": self.npartitions,\n            "lhs_name": self.lhs_name,\n            "lhs_npartitions": self.lhs_npartitions,\n            "rhs_name": self.rhs_name,\n            "rhs_npartitions": self.rhs_npartitions,\n            "parts_out": self.parts_out,\n            "merge_kwargs": _merge_kwargs,\n        }\n\n    @classmethod\n    def __dask_distributed_unpack__(cls, state, dsk, dependencies):\n        from distributed.worker import dumps_task\n\n        # Expand merge_kwargs\n        merge_kwargs = state.pop("merge_kwargs", {})\n        state.update(merge_kwargs)\n\n        # Materialize the layer\n        raw = cls(**state)._construct_graph(deserializing=True)\n\n        # Convert all keys to strings and dump tasks\n        raw = {stringify(k): stringify_collection_keys(v) for k, v in raw.items()}\n        keys = raw.keys() | dsk.keys()\n        deps = {k: keys_in_tasks(keys, [v]) for k, v in raw.items()}\n\n        return {"dsk": toolz.valmap(dumps_task, raw), "deps": deps}\n\n    def _keys_to_parts(self, keys):\n        """Simple utility to convert keys to partition indices."""\n        parts = set()\n        for key in keys:\n            try:\n                _name, _part = key\n            except ValueError:\n                continue\n            if _name != self.name:\n                continue\n            parts.add(_part)\n        return parts\n\n    @property\n    def _broadcast_plan(self):\n        # Return structure (tuple):\n        # (\n        #     <broadcasted-collection-name>,\n        #     <broadcasted-collection-npartitions>,\n        #     <other-collection-npartitions>,\n        #     <other-collection-on>,\n        # )\n        if self.lhs_npartitions < self.rhs_npartitions:\n            # Broadcasting the left\n            return (\n                self.lhs_name,\n                self.lhs_npartitions,\n                self.rhs_name,\n                self.right_on,\n            )\n        else:\n            # Broadcasting the right\n            return (\n                self.rhs_name,\n                self.rhs_npartitions,\n                self.lhs_name,\n                self.left_on,\n            )\n\n    def _cull_dependencies(self, keys, parts_out=None):\n        """Determine the necessary dependencies to produce `keys`.\n\n        For a broadcast join, output partitions always depend on\n        all partitions of the broadcasted collection, but only one\n        partition of the "other" collection.\n        """\n        # Get broadcast info\n        bcast_name, bcast_size, other_name = self._broadcast_plan[:3]\n\n        deps = defaultdict(set)\n        parts_out = parts_out or self._keys_to_parts(keys)\n        for part in parts_out:\n            deps[(self.name, part)] |= {(bcast_name, i) for i in range(bcast_size)}\n            deps[(self.name, part)] |= {\n                (other_name, part),\n            }\n        return deps\n\n    def _cull(self, parts_out):\n        return BroadcastJoinLayer(\n            self.name,\n            self.npartitions,\n            self.lhs_name,\n            self.lhs_npartitions,\n            self.rhs_name,\n            self.rhs_npartitions,\n            annotations=self.annotations,\n            parts_out=parts_out,\n            **self.merge_kwargs,\n        )\n\n    def cull(self, keys, all_keys):\n        """Cull a BroadcastJoinLayer HighLevelGraph layer.\n\n        The underlying graph will only include the necessary\n        tasks to produce the keys (indices) included in `parts_out`.\n        Therefore, "culling" the layer only requires us to reset this\n        parameter.\n        """\n        parts_out = self._keys_to_parts(keys)\n        culled_deps = self._cull_dependencies(keys, parts_out=parts_out)\n        if parts_out != set(self.parts_out):\n            culled_layer = self._cull(parts_out)\n            return culled_layer, culled_deps\n        else:\n            return self, culled_deps\n\n    def _construct_graph(self, deserializing=False):\n        """Construct graph for a broadcast join operation."""\n\n        inter_name = "inter-" + self.name\n        split_name = "split-" + self.name\n\n        if deserializing:\n            # Use CallableLazyImport objects to avoid importing dataframe\n            # module on the scheduler\n            split_partition_func = CallableLazyImport(\n                "dask.dataframe.multi._split_partition"\n            )\n            concat_func = CallableLazyImport("dask.dataframe.multi._concat_wrapper")\n            merge_chunk_func = CallableLazyImport(\n                "dask.dataframe.multi._merge_chunk_wrapper"\n            )\n        else:\n            # Not running on distributed scheduler - Use explicit functions\n            from dask.dataframe.multi import _concat_wrapper as concat_func\n            from dask.dataframe.multi import _merge_chunk_wrapper as merge_chunk_func\n            from dask.dataframe.multi import _split_partition as split_partition_func\n\n        # Get broadcast "plan"\n        bcast_name, bcast_size, other_name, other_on = self._broadcast_plan\n        bcast_side = "left" if self.lhs_npartitions < self.rhs_npartitions else "right"\n\n        # Loop over output partitions, which should be a 1:1\n        # mapping with the input partitions of "other".\n        # Culling should allow us to avoid generating tasks for\n        # any output partitions that are not requested (via `parts_out`)\n        dsk = {}\n        for i in self.parts_out:\n\n            # Split each "other" partition by hash\n            if self.how != "inner":\n                dsk[(split_name, i)] = (\n                    split_partition_func,\n                    (other_name, i),\n                    other_on,\n                    bcast_size,\n                )\n\n            # For each partition of "other", we need to join\n            # to each partition of "bcast". If it is a "left"\n            # or "right" join, there should be a unique mapping\n            # between the local splits of "other" and the\n            # partitions of "bcast" (which means we need an\n            # additional `getitem` operation to isolate the\n            # correct split of each "other" partition).\n            _concat_list = []\n            for j in range(bcast_size):\n                # Specify arg list for `merge_chunk`\n                _merge_args = [\n                    (\n                        operator.getitem,\n                        (split_name, i),\n                        j,\n                    )\n                    if self.how != "inner"\n                    else (other_name, i),\n                    (bcast_name, j),\n                ]\n                if bcast_side == "left":\n                    # If the left is broadcasted, the\n                    # arg list needs to be reversed\n                    _merge_args.reverse()\n                inter_key = (inter_name, i, j)\n                dsk[inter_key] = (\n                    apply,\n                    merge_chunk_func,\n                    _merge_args,\n                    self.merge_kwargs,\n                )\n                _concat_list.append(inter_key)\n\n            # Concatenate the merged results for each output partition\n            dsk[(self.name, i)] = (concat_func, _concat_list)\n\n        return dsk\n\n\nclass DataFrameIOLayer(Blockwise):\n    """DataFrame-based Blockwise Layer with IO\n\n    Parameters\n    ----------\n    name : str\n        Name to use for the constructed layer.\n    columns : str, list or None\n        Field name(s) to read in as columns in the output.\n    inputs : list or BlockwiseDep\n        List of arguments to be passed to ``io_func`` so\n        that the materialized task to produce partition ``i``\n        will be: ``(<io_func>, inputs[i])``.  Note that each\n        element of ``inputs`` is typically a tuple of arguments.\n    io_func : callable\n        A callable function that takes in a single tuple\n        of arguments, and outputs a DataFrame partition.\n        Column projection will be supported for functions\n        that satisfy the ``DataFrameIOFunction`` protocol.\n    label : str (optional)\n        String to use as a prefix in the place-holder collection\n        name. If nothing is specified (default), "subset-" will\n        be used.\n    produces_tasks : bool (optional)\n        Whether one or more elements of `inputs` is expected to\n        contain a nested task. This argument in only used for\n        serialization purposes, and will be deprecated in the\n        future. Default is False.\n    creation_info: dict (optional)\n        Dictionary containing the callable function (\'func\'),\n        positional arguments (\'args\'), and key-word arguments\n        (\'kwargs\') used to produce the dask collection with\n        this underlying ``DataFrameIOLayer``.\n    annotations: dict (optional)\n        Layer annotations to pass through to Blockwise.\n    """\n\n    def __init__(\n        self,\n        name,\n        columns,\n        inputs,\n        io_func,\n        label=None,\n        produces_tasks=False,\n        creation_info=None,\n        annotations=None,\n    ):\n        self.name = name\n        self._columns = columns\n        self.inputs = inputs\n        self.io_func = io_func\n        self.label = label\n        self.produces_tasks = produces_tasks\n        self.annotations = annotations\n        self.creation_info = creation_info\n\n        if not isinstance(inputs, BlockwiseDep):\n            # Define mapping between key index and "part"\n            io_arg_map = BlockwiseDepDict(\n                {(i,): inp for i, inp in enumerate(self.inputs)},\n                produces_tasks=self.produces_tasks,\n            )\n        else:\n            io_arg_map = inputs\n\n        # Use Blockwise initializer\n        dsk = {self.name: (io_func, blockwise_token(0))}\n        super().__init__(\n            output=self.name,\n            output_indices="i",\n            dsk=dsk,\n            indices=[(io_arg_map, "i")],\n            numblocks={},\n            annotations=annotations,\n        )\n\n    @property\n    def columns(self):\n        """Current column projection for this layer"""\n        return self._columns\n\n    def project_columns(self, columns):\n        """Produce a column projection for this IO layer.\n        Given a list of required output columns, this method\n        returns the projected layer.\n        """\n        from dask.dataframe.io.utils import DataFrameIOFunction\n\n        columns = list(columns)\n\n        if self.columns is None or set(self.columns).issuperset(columns):\n\n            # Apply column projection in IO function.\n            # Must satisfy `DataFrameIOFunction` protocol\n            if isinstance(self.io_func, DataFrameIOFunction):\n                io_func = self.io_func.project_columns(columns)\n            else:\n                io_func = self.io_func\n\n            layer = DataFrameIOLayer(\n                (self.label or "subset") + "-" + tokenize(self.name, columns),\n                columns,\n                self.inputs,\n                io_func,\n                label=self.label,\n                produces_tasks=self.produces_tasks,\n                annotations=self.annotations,\n            )\n            return layer\n        else:\n            # Default behavior\n            return self\n\n    def __repr__(self):\n        return "DataFrameIOLayer<name=\'{}\', n_parts={}, columns={}>".format(\n            self.name, len(self.inputs), self.columns\n        )\n\n\nclass DataFrameTreeReduction(Layer):\n    """DataFrame Tree-Reduction Layer\n\n    Parameters\n    ----------\n    name : str\n        Name to use for the constructed layer.\n    name_input : str\n        Name of the input layer that is being reduced.\n    npartitions_input : str\n        Number of partitions in the input layer.\n    concat_func : callable\n        Function used by each tree node to reduce a list of inputs\n        into a single output value. This function must accept only\n        a list as its first positional argument.\n    tree_node_func : callable\n        Function used on the output of ``concat_func`` in each tree\n        node. This function must accept the output of ``concat_func``\n        as its first positional argument.\n    finalize_func : callable, optional\n        Function used in place of ``tree_node_func`` on the final tree\n        node(s) to produce the final output for each split. By default,\n        ``tree_node_func`` will be used.\n    split_every : int, optional\n        This argument specifies the maximum number of input nodes\n        to be handled by any one task in the tree. Defaults to 32.\n    split_out : int, optional\n        This argument specifies the number of output nodes in the\n        reduction tree. If ``split_out`` is set to an integer >=1, the\n        input tasks must contain data that can be indexed by a ``getitem``\n        operation with a key in the range ``[0, split_out)``.\n    output_partitions : list, optional\n        List of required output partitions. This parameter is used\n        internally by Dask for high-level culling.\n    tree_node_name : str, optional\n        Name to use for intermediate tree-node tasks.\n    """\n\n    name: str\n    name_input: str\n    npartitions_input: int\n    concat_func: Callable\n    tree_node_func: Callable\n    finalize_func: Callable | None\n    split_every: int\n    split_out: int\n    output_partitions: list[int]\n    tree_node_name: str\n    widths: list[int]\n    height: int\n\n    def __init__(\n        self,\n        name: str,\n        name_input: str,\n        npartitions_input: int,\n        concat_func: Callable,\n        tree_node_func: Callable,\n        finalize_func: Callable | None = None,\n        split_every: int = 32,\n        split_out: int | None = None,\n        output_partitions: list[int] | None = None,\n        tree_node_name: str | None = None,\n        annotations: dict[str, Any] | None = None,\n    ):\n        super().__init__(annotations=annotations)\n        self.name = name\n        self.name_input = name_input\n        self.npartitions_input = npartitions_input\n        self.concat_func = concat_func\n        self.tree_node_func = tree_node_func\n        self.finalize_func = finalize_func\n        self.split_every = split_every\n        self.split_out = split_out  # type: ignore\n        self.output_partitions = (\n            list(range(self.split_out or 1))\n            if output_partitions is None\n            else output_partitions\n        )\n        self.tree_node_name = tree_node_name or "tree_node-" + self.name\n\n        # Calculate tree widths and height\n        # (Used to get output keys without materializing)\n        parts = self.npartitions_input\n        self.widths = [parts]\n        while parts > 1:\n            parts = math.ceil(parts / self.split_every)\n            self.widths.append(int(parts))\n        self.height = len(self.widths)\n\n    def _make_key(self, *name_parts, split=0):\n        # Helper function construct a key\n        # with a "split" element when\n        # bool(split_out) is True\n        return name_parts + (split,) if self.split_out else name_parts\n\n    def _define_task(self, input_keys, final_task=False):\n        # Define nested concatenation and func task\n        if final_task and self.finalize_func:\n            outer_func = self.finalize_func\n        else:\n            outer_func = self.tree_node_func\n        return (toolz.pipe, input_keys, self.concat_func, outer_func)\n\n    def _construct_graph(self):\n        """Construct graph for a tree reduction."""\n\n        dsk = {}\n        if not self.output_partitions:\n            return dsk\n\n        # Deal with `bool(split_out) == True`.\n        # These cases require that the input tasks\n        # return a type that enables getitem operation\n        # with indices: [0, split_out)\n        # Therefore, we must add "getitem" tasks to\n        # select the appropriate element for each split\n        name_input_use = self.name_input\n        if self.split_out:\n            name_input_use += "-split"\n            for s in self.output_partitions:\n                for p in range(self.npartitions_input):\n                    dsk[self._make_key(name_input_use, p, split=s)] = (\n                        operator.getitem,\n                        (self.name_input, p),\n                        s,\n                    )\n\n        if self.height >= 2:\n            # Loop over output splits\n            for s in self.output_partitions:\n                # Loop over reduction levels\n                for depth in range(1, self.height):\n                    # Loop over reduction groups\n                    for group in range(self.widths[depth]):\n                        # Calculate inputs for the current group\n                        p_max = self.widths[depth - 1]\n                        lstart = self.split_every * group\n                        lstop = min(lstart + self.split_every, p_max)\n                        if depth == 1:\n                            # Input nodes are from input layer\n                            input_keys = [\n                                self._make_key(name_input_use, p, split=s)\n                                for p in range(lstart, lstop)\n                            ]\n                        else:\n                            # Input nodes are tree-reduction nodes\n                            input_keys = [\n                                self._make_key(\n                                    self.tree_node_name, p, depth - 1, split=s\n                                )\n                                for p in range(lstart, lstop)\n                            ]\n\n                        # Define task\n                        if depth == self.height - 1:\n                            # Final Node (Use fused `self.tree_finalize` task)\n                            assert (\n                                group == 0\n                            ), f"group = {group}, not 0 for final tree reduction task"\n                            dsk[(self.name, s)] = self._define_task(\n                                input_keys, final_task=True\n                            )\n                        else:\n                            # Intermediate Node\n                            dsk[\n                                self._make_key(\n                                    self.tree_node_name, group, depth, split=s\n                                )\n                            ] = self._define_task(input_keys, final_task=False)\n        else:\n            # Deal with single-partition case\n            for s in self.output_partitions:\n                input_keys = [self._make_key(name_input_use, 0, split=s)]\n                dsk[(self.name, s)] = self._define_task(input_keys, final_task=True)\n\n        return dsk\n\n    def __repr__(self):\n        return "DataFrameTreeReduction<name=\'{}\', input_name={}, split_out={}>".format(\n            self.name, self.name_input, self.split_out\n        )\n\n    def _output_keys(self):\n        return {(self.name, s) for s in self.output_partitions}\n\n    def get_output_keys(self):\n        if hasattr(self, "_cached_output_keys"):\n            return self._cached_output_keys\n        else:\n            output_keys = self._output_keys()\n            self._cached_output_keys = output_keys\n        return self._cached_output_keys\n\n    def is_materialized(self):\n        return hasattr(self, "_cached_dict")\n\n    @property\n    def _dict(self):\n        """Materialize full dict representation"""\n        if hasattr(self, "_cached_dict"):\n            return self._cached_dict\n        else:\n            dsk = self._construct_graph()\n            self._cached_dict = dsk\n        return self._cached_dict\n\n    def __getitem__(self, key):\n        return self._dict[key]\n\n    def __iter__(self):\n        return iter(self._dict)\n\n    def __len__(self):\n        # Start with "base" tree-reduction size\n        tree_size = (sum(self.widths[1:]) or 1) * (self.split_out or 1)\n        if self.split_out:\n            # Add on "split-*" tasks used for `getitem` ops\n            return tree_size + self.npartitions_input * len(self.output_partitions)\n        return tree_size\n\n    def _keys_to_output_partitions(self, keys):\n        """Simple utility to convert keys to output partition indices."""\n        splits = set()\n        for key in keys:\n            try:\n                _name, _split = key\n            except ValueError:\n                continue\n            if _name != self.name:\n                continue\n            splits.add(_split)\n        return splits\n\n    def _cull(self, output_partitions):\n        return DataFrameTreeReduction(\n            self.name,\n            self.name_input,\n            self.npartitions_input,\n            self.concat_func,\n            self.tree_node_func,\n            finalize_func=self.finalize_func,\n            split_every=self.split_every,\n            split_out=self.split_out,\n            output_partitions=output_partitions,\n            tree_node_name=self.tree_node_name,\n            annotations=self.annotations,\n        )\n\n    def cull(self, keys, all_keys):\n        """Cull a DataFrameTreeReduction HighLevelGraph layer"""\n        deps = {\n            (self.name, 0): {\n                (self.name_input, i) for i in range(self.npartitions_input)\n            }\n        }\n        output_partitions = self._keys_to_output_partitions(keys)\n        if output_partitions != set(self.output_partitions):\n            culled_layer = self._cull(output_partitions)\n            return culled_layer, deps\n        else:\n            return self, deps\n\n    def __dask_distributed_pack__(self, *args, **kwargs):\n        from distributed.protocol.serialize import to_serialize\n\n        # Pickle the (possibly) user-defined functions here\n        _concat_func = to_serialize(self.concat_func)\n        _tree_node_func = to_serialize(self.tree_node_func)\n        if self.finalize_func:\n            _finalize_func = to_serialize(self.finalize_func)\n        else:\n            _finalize_func = None\n\n        return {\n            "name": self.name,\n            "name_input": self.name_input,\n            "npartitions_input": self.npartitions_input,\n            "concat_func": _concat_func,\n            "tree_node_func": _tree_node_func,\n            "finalize_func": _finalize_func,\n            "split_every": self.split_every,\n            "split_out": self.split_out,\n            "output_partitions": self.output_partitions,\n            "tree_node_name": self.tree_node_name,\n        }\n\n    @classmethod\n    def __dask_distributed_unpack__(cls, state, dsk, dependencies):\n        from distributed.protocol.serialize import to_serialize\n\n        # Materialize the layer\n        raw = cls(**state)._construct_graph()\n\n        # Convert all keys to strings and dump tasks\n        raw = {stringify(k): stringify_collection_keys(v) for k, v in raw.items()}\n        keys = raw.keys() | dsk.keys()\n        deps = {k: keys_in_tasks(keys, [v]) for k, v in raw.items()}\n\n        # Must use `to_serialize` on the entire task.\n        # This is required because the task-tuples contain `Serialized`\n        # function objects instead of real functions. Using `dumps_task`\n        # may or may not correctly wrap the entire tuple in `to_serialize`.\n        # So we use `to_serialize` here to be explicit. When the task\n        # arrives at a worker, both the `Serialized` task-tuples and the\n        # `Serialized` functions nested within them should be deserialzed\n        # automatically by the comm.\n        return {"dsk": toolz.valmap(to_serialize, raw), "deps": deps}\n',
            'dask/tests/test_distributed.py': 'import pytest\n\ndistributed = pytest.importorskip("distributed")\n\nimport asyncio\nimport os\nimport sys\nfrom functools import partial\nfrom operator import add\n\nfrom distributed.utils_test import cleanup  # noqa F401\nfrom distributed.utils_test import client as c  # noqa F401\nfrom distributed.utils_test import (  # noqa F401\n    cluster,\n    cluster_fixture,\n    gen_cluster,\n    loop,\n    loop_in_thread,\n    varying,\n)\n\nimport dask\nimport dask.bag as db\nfrom dask import compute, delayed, persist\nfrom dask.base import compute_as_if_collection, get_scheduler\nfrom dask.blockwise import Blockwise\nfrom dask.delayed import Delayed\nfrom dask.distributed import futures_of, wait\nfrom dask.highlevelgraph import HighLevelGraph, MaterializedLayer\nfrom dask.utils import get_named_args, tmpdir, tmpfile\nfrom dask.utils_test import inc\n\nif "should_check_state" in get_named_args(gen_cluster):\n    gen_cluster = partial(gen_cluster, should_check_state=False)\n    cluster = partial(cluster, should_check_state=False)\n\n\n# TODO: the fixture teardown for `cluster_fixture` is failing periodically with\n# a PermissionError on windows only (in CI). Since this fixture lives in the\n# distributed codebase and is nested within other fixtures we use, it\'s hard to\n# patch it from the dask codebase. And since the error is during fixture\n# teardown, an xfail won\'t cut it. As a hack, for now we skip all these tests\n# on windows. See https://github.com/dask/dask/issues/8877.\npytestmark = pytest.mark.skipif(\n    sys.platform == "win32",\n    reason=(\n        "The teardown of distributed.utils_test.cluster_fixture "\n        "fails on windows CI currently"\n    ),\n)\n\n\ndef test_can_import_client():\n    from dask.distributed import Client  # noqa: F401\n\n\ndef test_can_import_nested_things():\n    from dask.distributed.protocol import dumps  # noqa: F401\n\n\n@gen_cluster(client=True)\nasync def test_persist(c, s, a, b):\n    x = delayed(inc)(1)\n    (x2,) = persist(x)\n\n    await wait(x2)\n    assert x2.key in a.data or x2.key in b.data\n\n    y = delayed(inc)(10)\n    y2, one = persist(y, 1)\n\n    await wait(y2)\n    assert y2.key in a.data or y2.key in b.data\n\n\ndef test_persist_nested(c):\n    a = delayed(1) + 5\n    b = a + 1\n    c = a + 2\n    result = persist({"a": a, "b": [1, 2, b]}, (c, 2), 4, [5])\n    assert isinstance(result[0]["a"], Delayed)\n    assert isinstance(result[0]["b"][2], Delayed)\n    assert isinstance(result[1][0], Delayed)\n\n    sol = ({"a": 6, "b": [1, 2, 7]}, (8, 2), 4, [5])\n    assert compute(*result) == sol\n\n    res = persist([a, b], c, 4, [5], traverse=False)\n    assert res[0][0] is a\n    assert res[0][1] is b\n    assert res[1].compute() == 8\n    assert res[2:] == (4, [5])\n\n\ndef test_futures_to_delayed_dataframe(c):\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    df = pd.DataFrame({"x": [1, 2, 3]})\n\n    futures = c.scatter([df, df])\n    ddf = dd.from_delayed(futures)\n    dd.utils.assert_eq(ddf.compute(), pd.concat([df, df], axis=0))\n\n    # Make sure from_delayed is Blockwise\n    assert isinstance(ddf.dask.layers[ddf._name], Blockwise)\n\n    with pytest.raises(TypeError):\n        ddf = dd.from_delayed([1, 2])\n\n\ndef test_from_delayed_dataframe(c):\n    # Check that Delayed keys in the form of a tuple\n    # are properly serialized in `from_delayed`\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    df = pd.DataFrame({"x": range(20)})\n    ddf = dd.from_pandas(df, npartitions=2)\n    ddf = dd.from_delayed(ddf.to_delayed())\n    dd.utils.assert_eq(ddf, df, scheduler=c)\n\n\n@pytest.mark.parametrize("fuse", [True, False])\ndef test_fused_blockwise_dataframe_merge(c, fuse):\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    # Generate two DataFrames with more partitions than\n    # the `max_branch` default used for shuffling (32).\n    # We need a multi-stage shuffle to cover #7178 fix.\n    size = 35\n    df1 = pd.DataFrame({"x": range(size), "y": range(size)})\n    df2 = pd.DataFrame({"x": range(size), "z": range(size)})\n    ddf1 = dd.from_pandas(df1, npartitions=size) + 10\n    ddf2 = dd.from_pandas(df2, npartitions=5) + 10\n    df1 += 10\n    df2 += 10\n\n    with dask.config.set({"optimization.fuse.active": fuse}):\n        ddfm = ddf1.merge(ddf2, on=["x"], how="left")\n        ddfm.head()  # https://github.com/dask/dask/issues/7178\n        dfm = ddfm.compute().sort_values("x")\n        # We call compute above since `sort_values` is not\n        # supported in `dask.dataframe`\n    dd.utils.assert_eq(\n        dfm, df1.merge(df2, on=["x"], how="left").sort_values("x"), check_index=False\n    )\n\n\n@pytest.mark.parametrize(\n    "computation",\n    [\n        None,\n        "compute_as_if_collection",\n        "dask.compute",\n    ],\n)\n@pytest.mark.parametrize(\n    "scheduler, use_distributed",\n    [\n        (None, True),\n        # If scheduler is explicitly provided, this takes precedence\n        ("sync", False),\n    ],\n)\ndef test_default_scheduler_on_worker(c, computation, use_distributed, scheduler):\n    """Should a collection use its default scheduler or the distributed\n    scheduler when being computed within a task?\n    """\n\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    def foo():\n        size = 10\n        df = pd.DataFrame({"x": range(size), "y": range(size)})\n        ddf = dd.from_pandas(df, npartitions=2)\n        if computation is None:\n            ddf.compute(scheduler=scheduler)\n        elif computation == "dask.compute":\n            dask.compute(ddf, scheduler=scheduler)\n        elif computation == "compute_as_if_collection":\n            compute_as_if_collection(\n                ddf.__class__, ddf.dask, list(ddf.dask), scheduler=scheduler\n            )\n        else:\n            assert False\n\n        return True\n\n    res = c.submit(foo)\n    assert res.result() is True\n    # Count how many submits/update-graph were received by the scheduler\n    assert (\n        c.run_on_scheduler(\n            lambda dask_scheduler: sum(\n                len(comp.code) for comp in dask_scheduler.computations\n            )\n        )\n        == 2\n        if use_distributed\n        else 1\n    )\n\n\ndef test_futures_to_delayed_bag(c):\n    L = [1, 2, 3]\n\n    futures = c.scatter([L, L])\n    b = db.from_delayed(futures)\n    assert list(b) == L + L\n\n\ndef test_futures_to_delayed_array(c):\n    da = pytest.importorskip("dask.array")\n    from dask.array.utils import assert_eq\n\n    np = pytest.importorskip("numpy")\n    x = np.arange(5)\n\n    futures = c.scatter([x, x])\n    A = da.concatenate(\n        [da.from_delayed(f, shape=x.shape, dtype=x.dtype) for f in futures], axis=0\n    )\n    assert_eq(A.compute(), np.concatenate([x, x], axis=0))\n\n\n@pytest.mark.filterwarnings(\n    "ignore:Running on a single-machine scheduler when a distributed client "\n    "is active might lead to unexpected results."\n)\n@gen_cluster(client=True)\nasync def test_local_get_with_distributed_active(c, s, a, b):\n\n    with dask.config.set(scheduler="sync"):\n        x = delayed(inc)(1).persist()\n    await asyncio.sleep(0.01)\n    assert not s.tasks  # scheduler hasn\'t done anything\n\n    x = delayed(inc)(2).persist(scheduler="sync")  # noqa F841\n    await asyncio.sleep(0.01)\n    assert not s.tasks  # scheduler hasn\'t done anything\n\n\ndef test_to_hdf_distributed(c):\n    pytest.importorskip("numpy")\n    pytest.importorskip("pandas")\n\n    from dask.dataframe.io.tests.test_hdf import test_to_hdf\n\n    test_to_hdf()\n\n\n@pytest.mark.filterwarnings(\n    "ignore:Running on a single-machine scheduler when a distributed client "\n    "is active might lead to unexpected results."\n)\n@pytest.mark.parametrize(\n    "npartitions",\n    [\n        1,\n        pytest.param(\n            4,\n            marks=pytest.mark.xfail(reason="HDF not multi-process safe", strict=False),\n        ),\n        pytest.param(\n            10,\n            marks=pytest.mark.xfail(reason="HDF not multi-process safe", strict=False),\n        ),\n    ],\n)\ndef test_to_hdf_scheduler_distributed(npartitions, c):\n    pytest.importorskip("numpy")\n    pytest.importorskip("pandas")\n\n    from dask.dataframe.io.tests.test_hdf import test_to_hdf_schedulers\n\n    test_to_hdf_schedulers(None, npartitions)\n\n\n@gen_cluster(client=True)\nasync def test_serializable_groupby_agg(c, s, a, b):\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n    df = pd.DataFrame({"x": [1, 2, 3, 4], "y": [1, 0, 1, 0]})\n    ddf = dd.from_pandas(df, npartitions=2)\n\n    result = ddf.groupby("y", sort=False).agg("count", split_out=2)\n\n    # Check Culling and Compute\n    agg0 = await c.compute(result.partitions[0])\n    agg1 = await c.compute(result.partitions[1])\n    dd.utils.assert_eq(\n        pd.concat([agg0, agg1]),\n        pd.DataFrame({"x": [2, 2], "y": [0, 1]}).set_index("y"),\n    )\n\n\ndef test_futures_in_graph(c):\n    x, y = delayed(1), delayed(2)\n    xx = delayed(add)(x, x)\n    yy = delayed(add)(y, y)\n    xxyy = delayed(add)(xx, yy)\n\n    xxyy2 = c.persist(xxyy)\n    xxyy3 = delayed(add)(xxyy2, 10)\n\n    assert xxyy3.compute(scheduler="dask.distributed") == ((1 + 1) + (2 + 2)) + 10\n\n\ndef test_zarr_distributed_roundtrip(c):\n    da = pytest.importorskip("dask.array")\n    pytest.importorskip("zarr")\n\n    with tmpdir() as d:\n        a = da.zeros((3, 3), chunks=(1, 1))\n        a.to_zarr(d)\n        a2 = da.from_zarr(d)\n        da.assert_eq(a, a2, scheduler=c)\n        assert a2.chunks == a.chunks\n\n\ndef test_zarr_in_memory_distributed_err(c):\n    da = pytest.importorskip("dask.array")\n    zarr = pytest.importorskip("zarr")\n\n    chunks = (1, 1)\n    a = da.ones((3, 3), chunks=chunks)\n    z = zarr.zeros_like(a, chunks=chunks)\n\n    with pytest.raises(RuntimeError):\n        a.to_zarr(z)\n\n\ndef test_scheduler_equals_client(c):\n    x = delayed(lambda: 1)()\n    assert x.compute(scheduler=c) == 1\n    assert c.run_on_scheduler(lambda dask_scheduler: dask_scheduler.story(x.key))\n\n\n@gen_cluster(client=True)\nasync def test_await(c, s, a, b):\n    x = dask.delayed(inc)(1)\n    x = await x.persist()\n    assert x.key in s.tasks\n    assert a.data or b.data\n    assert all(f.done() for f in futures_of(x))\n\n\ndef test_local_scheduler():\n    async def f():\n        x = dask.delayed(inc)(1)\n        y = x + 1\n        z = await y.persist()\n        assert len(z.dask) == 1\n\n    asyncio.run(f())\n\n\n@gen_cluster(client=True)\nasync def test_annotations_blockwise_unpack(c, s, a, b):\n    da = pytest.importorskip("dask.array")\n    np = pytest.importorskip("numpy")\n    from dask.array.utils import assert_eq\n\n    # A flaky doubling function -- need extra args because it is called before\n    # application to establish dtype/meta.\n    scale = varying([ZeroDivisionError("one"), ZeroDivisionError("two"), 2, 2])\n\n    def flaky_double(x):\n        return scale() * x\n\n    # A reliable double function.\n    def reliable_double(x):\n        return 2 * x\n\n    x = da.ones(10, chunks=(5,))\n\n    # The later annotations should not override the earlier annotations\n    with dask.annotate(retries=2):\n        y = x.map_blocks(flaky_double, meta=np.array((), dtype=np.float_))\n    with dask.annotate(retries=0):\n        z = y.map_blocks(reliable_double, meta=np.array((), dtype=np.float_))\n\n    with dask.config.set(optimization__fuse__active=False):\n        z = await c.compute(z)\n\n    assert_eq(z, np.ones(10) * 4.0)\n\n\n@pytest.mark.parametrize(\n    "io",\n    [\n        "ones",\n        "zeros",\n        "full",\n    ],\n)\n@pytest.mark.parametrize("fuse", [True, False, None])\ndef test_blockwise_array_creation(c, io, fuse):\n    np = pytest.importorskip("numpy")\n    da = pytest.importorskip("dask.array")\n\n    chunks = (5, 2)\n    shape = (10, 4)\n\n    if io == "ones":\n        darr = da.ones(shape, chunks=chunks)\n        narr = np.ones(shape)\n    elif io == "zeros":\n        darr = da.zeros(shape, chunks=chunks)\n        narr = np.zeros(shape)\n    elif io == "full":\n        darr = da.full(shape, 10, chunks=chunks)\n        narr = np.full(shape, 10)\n\n    darr += 2\n    narr += 2\n    with dask.config.set({"optimization.fuse.active": fuse}):\n        darr.compute()\n        dsk = dask.array.optimize(darr.dask, darr.__dask_keys__())\n        # dsk should be a dict unless fuse is explicitly False\n        assert isinstance(dsk, dict) == (fuse is not False)\n        da.assert_eq(darr, narr, scheduler=c)\n\n\n@pytest.mark.filterwarnings(\n    "ignore:Running on a single-machine scheduler when a distributed client "\n    "is active might lead to unexpected results."\n)\n@pytest.mark.parametrize(\n    "io",\n    ["parquet-pyarrow", "parquet-fastparquet", "csv", "hdf"],\n)\n@pytest.mark.parametrize("fuse", [True, False, None])\n@pytest.mark.parametrize("from_futures", [True, False])\ndef test_blockwise_dataframe_io(c, tmpdir, io, fuse, from_futures):\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    df = pd.DataFrame({"x": [1, 2, 3] * 5, "y": range(15)})\n\n    if from_futures:\n        parts = [df.iloc[:5], df.iloc[5:10], df.iloc[10:15]]\n        futs = c.scatter(parts)\n        ddf0 = dd.from_delayed(futs, meta=parts[0])\n    else:\n        ddf0 = dd.from_pandas(df, npartitions=3)\n\n    if io.startswith("parquet"):\n        if io == "parquet-pyarrow":\n            pytest.importorskip("pyarrow.parquet")\n            engine = "pyarrow"\n        else:\n            pytest.importorskip("fastparquet")\n            engine = "fastparquet"\n        ddf0.to_parquet(str(tmpdir), engine=engine)\n        ddf = dd.read_parquet(str(tmpdir), engine=engine)\n    elif io == "csv":\n        ddf0.to_csv(str(tmpdir), index=False)\n        ddf = dd.read_csv(os.path.join(str(tmpdir), "*"))\n    elif io == "hdf":\n        pytest.importorskip("tables")\n        fn = str(tmpdir.join("h5"))\n        ddf0.to_hdf(fn, "/data*")\n        ddf = dd.read_hdf(fn, "/data*")\n\n    df = df[["x"]] + 10\n    ddf = ddf[["x"]] + 10\n    with dask.config.set({"optimization.fuse.active": fuse}):\n        ddf.compute()\n        dsk = dask.dataframe.optimize(ddf.dask, ddf.__dask_keys__())\n        # dsk should not be a dict unless fuse is explicitly True\n        assert isinstance(dsk, dict) == bool(fuse)\n\n        dd.assert_eq(ddf, df, check_index=False)\n\n\ndef test_blockwise_fusion_after_compute(c):\n    # See: https://github.com/dask/dask/issues/7720\n\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    # Simple sequence of Dask-Dataframe manipulations\n    df = pd.DataFrame({"x": [1, 2, 3] * 5})\n    series = dd.from_pandas(df, npartitions=2)["x"]\n    result = series < 3\n\n    # Trigger an optimization of the `series` graph\n    # (which `result` depends on), then compute `result`.\n    # This is essentially a test of `rewrite_blockwise`.\n    series_len = len(series)\n    assert series_len == 15\n    assert df.x[result.compute()].sum() == 15\n\n\n@gen_cluster(client=True)\nasync def test_blockwise_numpy_args(c, s, a, b):\n    """Test pack/unpack of blockwise that includes a NumPy literal argument"""\n    da = pytest.importorskip("dask.array")\n    np = pytest.importorskip("numpy")\n\n    def fn(x, dt):\n        assert type(dt) is np.uint16\n        return x.astype(dt)\n\n    arr = da.blockwise(\n        fn, "x", da.ones(1000), "x", np.uint16(42), None, dtype=np.uint16\n    )\n    res = await c.compute(arr.sum(), optimize_graph=False)\n    assert res == 1000\n\n\n@gen_cluster(client=True)\nasync def test_blockwise_numpy_kwargs(c, s, a, b):\n    """Test pack/unpack of blockwise that includes a NumPy literal keyword argument"""\n    da = pytest.importorskip("dask.array")\n    np = pytest.importorskip("numpy")\n\n    def fn(x, dt=None):\n        assert type(dt) is np.uint16\n        return x.astype(dt)\n\n    arr = da.blockwise(fn, "x", da.ones(1000), "x", dtype=np.uint16, dt=np.uint16(42))\n    res = await c.compute(arr.sum(), optimize_graph=False)\n    assert res == 1000\n\n\ndef test_blockwise_different_optimization(c):\n    # Regression test for incorrect results due to SubgraphCallable.__eq__\n    # not correctly handling subgraphs with the same outputs and arity but\n    # different internals (GH-7632). The bug is triggered by distributed\n    # because it uses a function cache.\n    da = pytest.importorskip("dask.array")\n    np = pytest.importorskip("numpy")\n\n    u = da.from_array(np.arange(3))\n    v = da.from_array(np.array([10 + 2j, 7 - 3j, 8 + 1j]))\n    cv = v.conj()\n    x = u * cv\n    (cv,) = dask.optimize(cv)\n    y = u * cv\n    expected = np.array([0 + 0j, 7 + 3j, 16 - 2j])\n    with dask.config.set({"optimization.fuse.active": False}):\n        x_value = x.compute()\n        y_value = y.compute()\n    np.testing.assert_equal(x_value, expected)\n    np.testing.assert_equal(y_value, expected)\n\n\ndef test_blockwise_cull_allows_numpy_dtype_keys(c):\n    # Regression test for https://github.com/dask/dask/issues/9072\n    da = pytest.importorskip("dask.array")\n    np = pytest.importorskip("numpy")\n\n    # Create a multi-block array.\n    x = da.ones((100, 100), chunks=(10, 10))\n\n    # Make a layer that pulls a block out of the array, but\n    # refers to that block using a numpy.int64 for the key rather\n    # than a python int.\n    name = next(iter(x.dask.layers))\n    block = {("block", 0, 0): (name, np.int64(0), np.int64(1))}\n    dsk = HighLevelGraph.from_collections("block", block, [x])\n    arr = da.Array(dsk, "block", ((10,), (10,)), dtype=x.dtype)\n\n    # Stick with high-level optimizations to force serialization of\n    # the blockwise layer.\n    with dask.config.set({"optimization.fuse.active": False}):\n        da.assert_eq(np.ones((10, 10)), arr, scheduler=c)\n\n\n@gen_cluster(client=True)\nasync def test_combo_of_layer_types(c, s, a, b):\n    """Check pack/unpack of a HLG that has every type of Layers!"""\n\n    da = pytest.importorskip("dask.array")\n    dd = pytest.importorskip("dask.dataframe")\n    np = pytest.importorskip("numpy")\n    pd = pytest.importorskip("pandas")\n\n    def add(x, y, z, extra_arg):\n        return x + y + z + extra_arg\n\n    y = c.submit(lambda x: x, 2)\n    z = c.submit(lambda x: x, 3)\n    x = da.blockwise(\n        add,\n        "x",\n        da.zeros((3,), chunks=(1,)),\n        "x",\n        da.ones((3,), chunks=(1,)),\n        "x",\n        y,\n        None,\n        concatenate=False,\n        dtype=int,\n        extra_arg=z,\n    )\n\n    df = dd.from_pandas(pd.DataFrame({"a": np.arange(3)}), npartitions=3)\n    df = df.shuffle("a", shuffle="tasks")\n    df = df["a"].to_dask_array()\n\n    res = x.sum() + df.sum()\n    res = await c.compute(res, optimize_graph=False)\n    assert res == 21\n\n\ndef test_blockwise_concatenate(c):\n    """Test a blockwise operation with concatenated axes"""\n    da = pytest.importorskip("dask.array")\n    np = pytest.importorskip("numpy")\n\n    def f(x, y):\n        da.assert_eq(y, [[0, 1, 2]])\n        return x\n\n    x = da.from_array(np.array([0, 1, 2]))\n    y = da.from_array(np.array([[0, 1, 2]]))\n    z = da.blockwise(\n        f,\n        ("i"),\n        x,\n        ("i"),\n        y,\n        ("ij"),\n        dtype=x.dtype,\n        concatenate=True,\n    )\n    c.compute(z, optimize_graph=False)\n    da.assert_eq(z, x, scheduler=c)\n\n\n@gen_cluster(client=True)\nasync def test_map_partitions_partition_info(c, s, a, b):\n    dd = pytest.importorskip("dask.dataframe")\n    pd = pytest.importorskip("pandas")\n\n    ddf = dd.from_pandas(pd.DataFrame({"a": range(10)}), npartitions=2)\n    res = await c.compute(\n        ddf.map_partitions(lambda x, partition_info=None: partition_info)\n    )\n    assert res[0] == {"number": 0, "division": 0}\n    assert res[1] == {"number": 1, "division": 5}\n\n\n@gen_cluster(client=True)\nasync def test_futures_in_subgraphs(c, s, a, b):\n    """Copied from distributed (tests/test_client.py)"""\n\n    dd = pytest.importorskip("dask.dataframe")\n    pd = pytest.importorskip("pandas")\n\n    ddf = dd.from_pandas(\n        pd.DataFrame(\n            dict(\n                uid=range(50),\n                enter_time=pd.date_range(\n                    start="2020-01-01", end="2020-09-01", periods=50, tz="UTC"\n                ),\n            )\n        ),\n        npartitions=1,\n    )\n\n    ddf = ddf[ddf.uid.isin(range(29))].persist()\n    ddf["day"] = ddf.enter_time.dt.day_name()\n    ddf = await c.submit(dd.categorical.categorize, ddf, columns=["day"], index=False)\n\n\n@pytest.mark.flaky(reruns=5, reruns_delay=5)\n@gen_cluster(client=True)\nasync def test_shuffle_priority(c, s, a, b):\n    pd = pytest.importorskip("pandas")\n    np = pytest.importorskip("numpy")\n    dd = pytest.importorskip("dask.dataframe")\n\n    # Test marked as "flaky" since the scheduling behavior\n    # is not deterministic. Note that the test is still\n    # very likely to fail every time if the "split" tasks\n    # are not prioritized correctly\n\n    df = pd.DataFrame({"a": range(1000)})\n    ddf = dd.from_pandas(df, npartitions=10)\n    ddf2 = ddf.shuffle("a", shuffle="tasks", max_branch=32)\n    await c.compute(ddf2)\n\n    # Parse transition log for processing tasks\n    log = [\n        eval(l[0])[0]\n        for l in s.transition_log\n        if l[1] == "processing" and "simple-shuffle-" in l[0]\n    ]\n\n    # Make sure most "split" tasks are processing before\n    # any "combine" tasks begin\n    late_split = np.quantile(\n        [i for i, st in enumerate(log) if st.startswith("split")], 0.75\n    )\n    early_combine = np.quantile(\n        [i for i, st in enumerate(log) if st.startswith("simple")], 0.25\n    )\n    assert late_split < early_combine\n\n\n@gen_cluster(client=True)\nasync def test_map_partitions_da_input(c, s, a, b):\n    """Check that map_partitions can handle a dask array input"""\n    np = pytest.importorskip("numpy")\n    pd = pytest.importorskip("pandas")\n    da = pytest.importorskip("dask.array")\n    datasets = pytest.importorskip("dask.datasets")\n\n    def f(d, a):\n        assert isinstance(d, pd.DataFrame)\n        assert isinstance(a, np.ndarray)\n        return d\n\n    df = datasets.timeseries(freq="1d").persist()\n    arr = da.ones((1,), chunks=1).persist()\n    await c.compute(df.map_partitions(f, arr, meta=df._meta))\n\n\ndef test_map_partitions_df_input():\n    """\n    Check that map_partitions can handle a delayed\n    partition of a dataframe input\n    """\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n\n    def f(d, a):\n        assert isinstance(d, pd.DataFrame)\n        assert isinstance(a, pd.DataFrame)\n        return d\n\n    def main():\n        item_df = dd.from_pandas(pd.DataFrame({"a": range(10)}), npartitions=1)\n        ddf = item_df.to_delayed()[0].persist()\n        merged_df = dd.from_pandas(pd.DataFrame({"b": range(10)}), npartitions=1)\n\n        # Notice, we include a shuffle in order to trigger a complex culling\n        merged_df = merged_df.shuffle(on="b")\n\n        merged_df.map_partitions(\n            f, ddf, meta=merged_df, enforce_metadata=False\n        ).compute()\n\n    with distributed.LocalCluster(\n        scheduler_port=0,\n        # Explicitly disabling dashboard to prevent related warnings being\n        # elevated to errors until `bokeh=3` is fully supported.\n        # See https://github.com/dask/dask/issues/9686 and\n        # https://github.com/dask/distributed/issues/7173 for details.\n        dashboard_address=":0",\n        scheduler_kwargs={"dashboard": False},\n        asynchronous=False,\n        n_workers=1,\n        nthreads=1,\n        processes=False,\n    ) as cluster:\n        with distributed.Client(cluster, asynchronous=False):\n            main()\n\n\n@gen_cluster(client=True)\nasync def test_annotation_pack_unpack(c, s, a, b):\n    hlg = HighLevelGraph({"l1": MaterializedLayer({"n": 42})}, {"l1": set()})\n\n    annotations = {"workers": ("alice",)}\n    packed_hlg = hlg.__dask_distributed_pack__(c, ["n"], annotations)\n\n    unpacked_hlg = HighLevelGraph.__dask_distributed_unpack__(packed_hlg)\n    annotations = unpacked_hlg["annotations"]\n    assert annotations == {"workers": {"n": ("alice",)}}\n\n\n@gen_cluster(client=True)\nasync def test_pack_MaterializedLayer_handles_futures_in_graph_properly(c, s, a, b):\n    fut = c.submit(inc, 1)\n\n    hlg = HighLevelGraph(\n        {"l1": MaterializedLayer({"x": fut, "y": (inc, "x"), "z": (inc, "y")})},\n        {"l1": set()},\n    )\n    # fill hlg.key_dependencies cache. This excludes known futures, so only\n    # includes a subset of all dependencies. Previously if the cache was present\n    # the future dependencies would be missing when packed.\n    hlg.get_all_dependencies()\n    packed = hlg.__dask_distributed_pack__(c, ["z"], {})\n    unpacked = HighLevelGraph.__dask_distributed_unpack__(packed)\n    assert unpacked["deps"] == {"x": {fut.key}, "y": {fut.key}, "z": {"y"}}\n\n\n@pytest.mark.filterwarnings(\n    "ignore:Running on a single-machine scheduler when a distributed client "\n    "is active might lead to unexpected results."\n)\n@gen_cluster(client=True)\nasync def test_to_sql_engine_kwargs(c, s, a, b):\n    # https://github.com/dask/dask/issues/8738\n    pd = pytest.importorskip("pandas")\n    dd = pytest.importorskip("dask.dataframe")\n    pytest.importorskip("sqlalchemy")\n\n    df = pd.DataFrame({"a": range(10), "b": range(10)})\n    df.index.name = "index"\n    ddf = dd.from_pandas(df, npartitions=1)\n    with tmpfile() as f:\n        uri = f"sqlite:///{f}"\n        result = ddf.to_sql(\n            "test", uri, index=True, engine_kwargs={"echo": False}, compute=False\n        )\n        await c.compute(result)\n\n        dd.utils.assert_eq(\n            ddf,\n            dd.read_sql_table("test", uri, "index"),\n            check_divisions=False,\n        )\n\n\n@gen_cluster(client=True)\nasync def test_non_recursive_df_reduce(c, s, a, b):\n    # See https://github.com/dask/dask/issues/8773\n\n    dd = pytest.importorskip("dask.dataframe")\n    pd = pytest.importorskip("pandas")\n\n    class SomeObject:\n        def __init__(self, val):\n            self.val = val\n\n    N = 170\n    series = pd.Series(data=[1] * N, index=range(2, N + 2))\n    dask_series = dd.from_pandas(series, npartitions=34)\n    result = dask_series.reduction(\n        chunk=lambda x: x,\n        aggregate=lambda x: SomeObject(x.sum().sum()),\n        split_every=False,\n        token="commit-dataset",\n        meta=object,\n    )\n\n    assert (await c.compute(result)).val == 170\n\n\ndef test_set_index_no_resursion_error(c):\n    # see: https://github.com/dask/dask/issues/8955\n    pytest.importorskip("dask.dataframe")\n    try:\n        ddf = (\n            dask.datasets.timeseries(start="2000-01-01", end="2000-07-01", freq="12h")\n            .reset_index()\n            .astype({"timestamp": str})\n        )\n        ddf = ddf.set_index("timestamp", sorted=True)\n        ddf.compute()\n    except RecursionError:\n        pytest.fail("dd.set_index triggered a recursion error")\n\n\ndef test_get_scheduler_without_distributed_raises():\n    msg = "no Client"\n    with pytest.raises(RuntimeError, match=msg):\n        get_scheduler(scheduler="dask.distributed")\n\n    with pytest.raises(RuntimeError, match=msg):\n        get_scheduler(scheduler="distributed")\n\n\ndef test_get_scheduler_with_distributed_active(c):\n    assert get_scheduler() == c.get\n    warning_message = (\n        "Running on a single-machine scheduler when a distributed client "\n        "is active might lead to unexpected results."\n    )\n    with pytest.warns(UserWarning, match=warning_message) as user_warnings_a:\n        get_scheduler(scheduler="threads")\n        get_scheduler(scheduler="sync")\n    assert len(user_warnings_a) == 2\n\n\ndef test_get_scheduler_with_distributed_active_reset_config(c):\n    assert get_scheduler() == c.get\n    with dask.config.set(scheduler="threads"):\n        with pytest.warns(UserWarning):\n            assert get_scheduler() != c.get\n        with dask.config.set(scheduler=None):\n            assert get_scheduler() == c.get\n',
        }
